column.value:
{
  "pageDescription": "Sample Creation & Full Metadata Capture",
  "dataPoints": {
    "sampleIdentity": {
      "uniqueSampleId": {"type": "system", "label": "Unique Sample ID (system)"},
      "sampleName": {"type": "text", "label": "Sample name", "required": true},
      "sampleCategory": {"type": "choice", "label": "Sample category", "options": ["Pharmaceutical", "Natural / Herbal", "Biological / Stability", "Microbiological / Environmental"], "required": true}
    },
    "sampleMaterial": {
      "materialType": {"type": "choice", "label": "Sample type & material", "options": ["API", "Excipient", "Bulk powder", "Intermediate", "Finished dosage form (tablet, capsule, injection, cream, patch)", "Reference / impurity standard", "Plant part (root, leaf, stem, flower)", "Blood / plasma / urine / saliva / CSF", "Animal tissue / organ / feces", "Cell culture sample", "Culture", "Water (PW, WFI)", "Environmental / equipment swab"], "required": true}
    },
    "coreMetadata": {
      "chemicalName": {"type": "text", "label": "Chemical / IUPAC name", "required": false},
      "grade": {"type": "text", "label": "Grade / specification", "required": false},
      "lotNumber": {"type": "text", "label": "Lot / batch number", "required": true},
      "dateOfManufacture": {"type": "date", "label": "Date of manufacture", "required": true},
      "expiryOrRetestDate": {"type": "date", "label": "Expiry or re-test date", "required": true},
      "storageCondition": {"type": "text", "label": "Storage condition (e.g., 25 C / 60% RH)", "required": false},
      "ownerOrRequester": {"type": "text", "label": "Owner / requester", "required": false},
      "chainOfCustodyStart": {"type": "dateTime", "label": "Chain-of-custody start", "required": false}
    },
    "clinicalMetadata": {
      "patientId": {"type": "text", "label": "Patient ID (if applicable)", "required": false},
      "clinicalTrialNumber": {"type": "text", "label": "Clinical trial number", "required": false},
      "consentStatus": {"type": "choice", "label": "Consent status", "options": ["Yes", "No", "Not applicable"], "required": false}
    }
  },
  "systemActions": ["Create sample record", "Generate barcode/QR label", "Set status: Created - Pending QC"],
  "nextPage": "Raw Sample Quality Check (QC)"
}
